/* ---- Branch ---- */
static void
op_bpl(struct cpu *cpu)
{
	cpu->last_cycles = 2 + do_branch(cpu, !(cpu->p & FLAG_NEGATIVE));
}
static void
op_bmi(struct cpu *cpu)
{
	cpu->last_cycles = 2 + do_branch(cpu, (cpu->p & FLAG_NEGATIVE));
}
static void
op_bvc(struct cpu *cpu)
{
	cpu->last_cycles = 2 + do_branch(cpu, !(cpu->p & FLAG_OVERFLOW));
}
