/* ---- INX / INY ---- */
static void
op_inx(struct cpu *cpu)
{
	read_byte(cpu, cpu->pc); /* cycle 2: dummy read */
	cpu->x++;
	update_nz(cpu, cpu->x);
	cpu->last_cycles = 2;
}
