/* ---- RLA (ROL+AND, RMW) ---- */
static void
rla_core(struct cpu *cpu, uint16_t a)
{
	uint8_t old_c, t;

	t = read_byte(cpu, a);
	write_byte_dummy(cpu, a, t);
	old_c = (cpu->p & FLAG_CARRY) ? 1 : 0;
	set_flag(cpu, FLAG_CARRY, (t & 0x80) != 0);
	t = (t << 1) | old_c;
	cpu->a &= t;
	update_nz(cpu, cpu->a);
	write_byte(cpu, a, t);
}
