/* ---- Undocumented NOPs ---- */
static void
op_nop_imp(struct cpu *cpu)
{
	read_byte(cpu, cpu->pc); /* cycle 2: dummy read */
	cpu->last_cycles = 2;
}
static void
op_nop_zp(struct cpu *cpu)
{
	(void)read_byte(cpu, addr_zp(cpu));
	cpu->last_cycles = 3;
}
