extern uint32_t opt_baud;


/* ------------------------------------------------------------------ */
/*  Signal handler                                                      */
/* ------------------------------------------------------------------ */

static void
handle_signal(int sig)
{
	(void)sig;
	if (g_debug_enabled != 0) {
		g_debug_break = 1;
	} else {
		/* exit() triggers atexit handlers (terminal restore) */
		exit(0);
	}
}

